-- Criminal Empire Online v0.6 — Game Map & Territories seed data

ON DUPLICATE KEY UPDATE name=VALUES(name), description=VALUES(description), map_asset=VALUES(map_asset), overlay_asset=VALUES(overlay_asset), region_type=VALUES(region_type), travel_cost_cash=VALUES(travel_cost_cash), travel_cost_energy=VALUES(travel_cost_energy), base_heat=VALUES(base_heat), police_pressure=VALUES(police_pressure), danger_level=VALUES(danger_level), recommended_level=VALUES(recommended_level), sort_order=VALUES(sort_order), is_active=VALUES(is_active), updated_at=NOW();

ON DUPLICATE KEY UPDATE region_id=VALUES(region_id), name=VALUES(name), description=VALUES(description), location_type=VALUES(location_type), x_percent=VALUES(x_percent), y_percent=VALUES(y_percent), heat_level=VALUES(heat_level), police_pressure=VALUES(police_pressure), danger_level=VALUES(danger_level), min_level=VALUES(min_level), linked_feature_key=VALUES(linked_feature_key), available_actions_json=VALUES(available_actions_json), sort_order=VALUES(sort_order), is_active=VALUES(is_active), updated_at=NOW();

UPDATE world_locations SET linked_territory_id = (SELECT id FROM territories WHERE name = 'Downtown' LIMIT 1) WHERE slug = 'downtown';
UPDATE world_locations SET linked_territory_id = (SELECT id FROM territories WHERE name = 'Old Town' LIMIT 1) WHERE slug = 'old-town-city';
UPDATE world_locations SET linked_territory_id = (SELECT id FROM territories WHERE name = 'Industrial Zone' LIMIT 1) WHERE slug = 'warehouses';
UPDATE world_locations SET linked_territory_id = (SELECT id FROM territories WHERE name = 'Harbor' LIMIT 1) WHERE slug = 'harbor-road';
UPDATE world_locations SET linked_territory_id = (SELECT id FROM territories WHERE name = 'Luxury Hills' LIMIT 1) WHERE slug = 'private-estates';
UPDATE world_locations SET linked_territory_id = (SELECT id FROM territories WHERE name = 'Old Town' LIMIT 1) WHERE slug = 'old-apartments';

ON DUPLICATE KEY UPDATE label=VALUES(label), route_hint=VALUES(route_hint), min_level=VALUES(min_level), is_active=VALUES(is_active), sort_order=VALUES(sort_order), updated_at=NOW();

SELECT territory.id, region.id, location.id, 'normal', 1, NOW(), NOW()
FROM world_locations location
JOIN world_regions region ON region.id = location.region_id
JOIN territories territory ON territory.id = location.linked_territory_id
WHERE location.linked_territory_id IS NOT NULL
ON DUPLICATE KEY UPDATE world_location_id=VALUES(world_location_id), updated_at=NOW();

SELECT users.id, region.id, location.id, NOW(), NOW()
FROM users
JOIN world_regions region ON region.slug = 'main-city'
JOIN world_locations location ON location.slug = 'slums'
WHERE NOT EXISTS (SELECT 1 FROM user_location_state state WHERE state.user_id = users.id);

